};

module.exports = async (api, event, args, startTime, loadData, saveData, automicTimers, config, hostingInfo, botSentMessages) => {
  const threadID = event.threadID;
  const ids = (botSentMessages[threadID] || []).slice();

  if (ids.length === 0) return;

  // Delete from newest to oldest
  const toDelete = ids.reverse().slice(0, 30);

  for (const msgID of toDelete) {
    try {
      await api.unsendMessage(msgID);
    } catch {}
    await new Promise(r => setTimeout(r, 300));
  }

  // Clear tracked list for this thread
  botSentMessages[threadID] = [];
};

const ws3 = require("ws3-fca");
const fs = require("fs");
const os = require("os");

process.on("uncaughtException", (err) => {
  console.log("خطأ:", err.message);
});

process.on("unhandledRejection", (reason) => {
  console.log("خطأ:", reason);
});

const config = {
  BOT_NAME: "ᴹᵃʳᶜᵒ",
  DEV_ID: "61589645620146"
};

const appState = JSON.parse(fs.readFileSync("appState.json", "utf8"));

function loadData() {
  try {
    return JSON.parse(fs.readFileSync("data.json", "utf8"));
  } catch {
    return { prefix: "!", freePrefix: false, protected: {}, savedMessages: [] };
  }
}

function saveData(data) {
  fs.writeFileSync("data.json", JSON.stringify(data, null, 2));
}

const commands = {};
fs.readdirSync("./commands").forEach(file => {
  if (file.endsWith(".js")) {
    commands[file.replace(".js", "")] = require(`./commands/${file}`);
  }
});

const events = {};
fs.readdirSync("./events").forEach(file => {
  if (file.endsWith(".js")) {
    events[file.replace(".js", "")] = require(`./events/${file}`);
  }
});

const automicTimers = {};

// Track message IDs sent by the bot per thread (up to 50 per thread)
const botSentMessages = {};

function trackMsg(threadID, msgID) {
  if (!threadID || !msgID) return;
  if (!botSentMessages[threadID]) botSentMessages[threadID] = [];
  botSentMessages[threadID].push(msgID);
  if (botSentMessages[threadID].length > 50) botSentMessages[threadID].shift();
}

ws3.login({ appState }, (err, api) => {
  if (err) return console.log("خطأ في تسجيل الدخول:", err);

  console.log("✅ البوت يعمل");

  const BOT_ID = api.getCurrentUserID();
  console.log("🤖 ID البوت:", BOT_ID);

  // Wrap api.sendMessage to track sent message IDs
  const _origSend = api.sendMessage.bind(api);
  api.sendMessage = (msg, threadID, cb) => {
    if (typeof cb === "function") {
      return _origSend(msg, threadID, (err2, info) => {
        if (!err2 && info?.messageID) trackMsg(threadID, info.messageID);
        cb(err2, info);
      });
    }
    const p = _origSend(msg, threadID);
    if (p && typeof p.then === "function") {
      return p.then(info => {
        if (info?.messageID) trackMsg(threadID, info.messageID);
        return info;
      });
    }
    return p;
  };

  const startTime = Date.now();
  const hostingInfo = {
    platform: os.platform(),
    arch: os.arch(),
    node: process.version,
    hostname: os.hostname()
  };

  api.listenMqtt((err, event) => {
    if (err || !event) return;

    for (const e in events) {
      try {
        events[e](api, event, config, loadData, saveData, automicTimers);
      } catch {}
    }

    if (!event.body) return;

    const body = event.body.trim();
    const data = loadData();
    const PREFIX = data.prefix || "!";
    const freePrefix = data.freePrefix || false;

    let cmd = null;
    let args = [];

    if (body.startsWith(PREFIX)) {
      args = body.slice(PREFIX.length).trim().split(" ");
      cmd = args[0].toLowerCase();
    } else if (freePrefix) {
      args = body.trim().split(" ");
      cmd = args[0].toLowerCase();
    }

    if (!cmd) return;

    // Only DEV_ID can run commands
    if (event.senderID !== config.DEV_ID) {
      return;
    }

    if (commands[cmd]) {
      try {
        const result = commands[cmd](
          api, event, args, startTime,
          loadData, saveData, automicTimers,
          config, hostingInfo, botSentMessages
        );
        if (result && typeof result.catch === "function") {
          result.catch(e => console.log("خطأ في الأمر:", e.message));
        }
      } catch (e) {
        console.log("خطأ في الأمر:", e.message);
      }
    }
  });
});

