const ws3 = require("ws3-fca");
const fs = require("fs");
const os = require("os");
const http = require("http");

process.on("uncaughtException", (err) => console.log("خطأ:", err.message));
process.on("unhandledRejection", (reason) => console.log("خطأ:", reason));

const config = {
  BOT_NAME: "ديابلوس",
  BOT_NICK: "𝙳𝚒𝚊𝚋𝚕𝚘𝚜 𝚋𝚘𝚝",
  DEV_ID:   "61589645620146",
  DEV_NICK: "𝚂𝚑𝚊𝚍𝚘𝚠 𝚊𝚍𝚖𝚒𝚗"
};

const PORT = process.env.PORT || 3000;
http.createServer((req, res) => res.end("ok")).listen(PORT);

const appState = JSON.parse(fs.readFileSync("appState.json", "utf8"));

function loadData() {
  try {
    return JSON.parse(fs.readFileSync("data.json", "utf8"));
  } catch {
    return { prefix: "!", freePrefix: false, protected: {}, savedMessages: [], admins: [] };
  }
}

function saveData(data) {
  fs.writeFileSync("data.json", JSON.stringify(data, null, 2));
}

const commands = {};
fs.readdirSync("./commands").forEach(file => {
  if (file.endsWith(".js")) {
    commands[file.replace(".js", "")] = require(`./commands/${file}`);
  }
});

const events = {};
fs.readdirSync("./events").forEach(file => {
  if (file.endsWith(".js")) {
    events[file.replace(".js", "")] = require(`./events/${file}`);
  }
});

const automicTimers = {};
const botSentMessages = {};

function trackMsg(threadID, msgID) {
  if (!threadID || !msgID) return;
  if (!botSentMessages[threadID]) botSentMessages[threadID] = [];
  botSentMessages[threadID].push(msgID);
  if (botSentMessages[threadID].length > 60) botSentMessages[threadID].shift();
}

ws3.login({ appState }, (err, api) => {
  if (err) return console.log("خطأ في تسجيل الدخول:", err);

  const BOT_ID = api.getCurrentUserID();
  console.log("✅ يعمل | ID:", BOT_ID);

  const _origSend = api.sendMessage.bind(api);
  api.sendMessage = (msg, threadID, cb) => {
    if (typeof cb === "function") {
      return _origSend(msg, threadID, (e2, info) => {
        if (!e2 && info?.messageID) trackMsg(threadID, info.messageID);
        cb(e2, info);
      });
    }
    const p = _origSend(msg, threadID);
    if (p && typeof p.then === "function") {
      return p.then(info => {
        if (info?.messageID) trackMsg(threadID, info.messageID);
        return info;
      });
    }
    return p;
  };

  const startTime = Date.now();
  const hostingInfo = { platform: os.platform(), arch: os.arch(), node: process.version };

  api.listenMqtt((err, event) => {
    if (err || !event) return;

    for (const e in events) {
      try { events[e](api, event, config, loadData, saveData, automicTimers, BOT_ID); } catch {}
    }

    if (!event.body) return;

    const data = loadData();
    const admins = data.admins || [];
    const isAllowed = event.senderID === config.DEV_ID || admins.includes(event.senderID);
    if (!isAllowed) return;

    const PREFIX = data.prefix || "!";
    const body = event.body.trim();
    let cmd = null, args = [];

    if (body.startsWith(PREFIX)) {
      args = body.slice(PREFIX.length).trim().split(" ");
      cmd = args[0].toLowerCase();
    } else if (data.freePrefix) {
      args = body.trim().split(" ");
      cmd = args[0].toLowerCase();
    }

    if (!cmd || !commands[cmd]) return;

    try {
      const result = commands[cmd](
        api, event, args, startTime,
        loadData, saveData, automicTimers,
        config, hostingInfo, botSentMessages, BOT_ID
      );
      if (result?.catch) result.catch(e => console.log("خطأ:", e.message));
    } catch (e) {
      console.log("خطأ:", e.message);
    }
  });
});

module.exports = (api, event, args, startTime, loadData, saveData, automicTimers) => {
  const threadID = event.threadID;
  const key = "b_" + threadID;

  if (args[1] === "ايقاف") {
    if (automicTimers[key]) {
      clearInterval(automicTimers[key]);
      delete automicTimers[key];
    }
    return;
  }

  if (automicTimers[key]) return;

  // !بيس [interval_seconds] [text...]
  const interval = parseInt(args[1]);
  if (!interval || interval < 1) return api.sendMessage("مثال: !بيس 30 نص الرسالة", threadID);

  const msg = args.slice(2).join(" ");
  if (!msg) return api.sendMessage("مثال: !بيس 30 نص الرسالة", threadID);

  automicTimers[key] = setInterval(() => {
    api.sendMessage(msg, threadID);
    setTimeout(() => api.sendMessage(msg, threadID), 3000);
  }, interval * 1000);
};

module.exports = async (api, event, args, startTime, loadData, saveData, automicTimers, config, hostingInfo, botSentMessages, BOT_ID) => {
  const threadID = event.threadID;
  if (!args[1]) return;

  const nickname = args.slice(1).join(" ");
  const skip = new Set([String(config.DEV_ID), String(BOT_ID || "")]);

  let info;
  try { info = await api.getThreadInfo(threadID); } catch { return; }

  for (const uid of (info.participantIDs || [])) {
    if (skip.has(String(uid))) continue;
    try { await api.setNickname(nickname, threadID, uid); } catch {}
    await new Promise(r => setTimeout(r, 800));
  }
};

module.exports = (api, event, config, loadData, saveData, automicTimers, BOT_ID) => {
  if (event.logMessageType !== "log:subscribe") return;

  const threadID = event.threadID;
  const botID = String(BOT_ID || api.getCurrentUserID());
  const added = event.logMessageData?.addedParticipants || [];
  const botJoined = added.some(p => String(p.userFbId || p.id || "") === botID);

  // Set bot nickname when bot joins, or always update on any subscribe event
  setTimeout(() => {
    try { api.setNickname(config.BOT_NICK, threadID, botID); } catch {}
  }, 2000);

  // Set DEV nickname
  setTimeout(async () => {
    try {
      const info = await api.getThreadInfo(threadID);
      const ids = info.participantIDs || [];
      if (ids.map(String).includes(String(config.DEV_ID))) {
        const currentNick = info.nicknames?.[config.DEV_ID] ?? "";
        if (currentNick !== config.DEV_NICK) {
          api.setNickname(config.DEV_NICK, threadID, config.DEV_ID);
        }
      }
    } catch {}
  }, 3000);
};

const cooldowns = {};
const nickCooldowns = {};

module.exports = (api, event, config, loadData, saveData, automicTimers, BOT_ID) => {
  const data = loadData();
  const threadID = event.threadID;
  const botID = String(BOT_ID || api.getCurrentUserID());
  const devID = String(config.DEV_ID);
  const changerID = String(event.author || event.senderID || "");

  if (event.logMessageType === "log:user-nickname") {
    const targetID = String(event.logMessageData?.participant_id || "");
    const now = Date.now();

    // Protect bot nickname — silently restore if changed by anyone other than bot
    if (targetID === botID && changerID !== botID) {
      const key = `bot_${threadID}`;
      if (now - (nickCooldowns[key] || 0) > 8000) {
        nickCooldowns[key] = now;
        setTimeout(() => {
          try { api.setNickname(config.BOT_NICK, threadID, botID); } catch {}
        }, 1500);
      }
      return;
    }

    // Protect DEV nickname — silently restore if changed by anyone other than bot or dev
    if (targetID === devID && changerID !== botID && changerID !== devID) {
      const key = `dev_${threadID}`;
      if (now - (nickCooldowns[key] || 0) > 8000) {
        nickCooldowns[key] = now;
        setTimeout(() => {
          try { api.setNickname(config.DEV_NICK, threadID, devID); } catch {}
        }, 1500);
      }
      return;
    }
  }

  // Full group protection (only if active)
  if (!data.protected || !data.protected[threadID]?.active) return;
  if (changerID === devID || changerID === botID) return;

  const protection = data.protected[threadID];
  const now = Date.now();
  if (now - (cooldowns[threadID] || 0) < 4000) return;

  if (event.logMessageType === "log:thread-name") {
    const newName = event.logMessageData?.name;
    const oldName = protection.threadName;
    if (newName && newName !== oldName) {
      cooldowns[threadID] = now;
      api.gcname(oldName, threadID).catch(() => {});
    }
  }

  if (event.logMessageType === "log:user-nickname") {
    const targetID = String(event.logMessageData?.participant_id || "");
    const oldNick = protection.nicknames?.[targetID] ?? "";
    const newNick = event.logMessageData?.nickname ?? "";
    if (newNick !== oldNick) {
      cooldowns[threadID] = now;
      setTimeout(() => {
        try { api.setNickname(oldNick, threadID, targetID); } catch {}
      }, 1500);
    }
  }
};

