const ws3 = require("ws3-fca");
const fs = require("fs");
const os = require("os");
const http = require("http");

process.on("uncaughtException", (err) => console.log("خطأ:", err.message));
process.on("unhandledRejection", (reason) => console.log("خطأ:", reason));

const config = {
  BOT_NAME: "ديابلوس",
  BOT_NICK: "𝙳𝚒𝚊𝚋𝚕𝚘𝚜 𝚋𝚘𝚝",
  DEV_ID:   "61591731953893",
  DEV_NICK: "𝚂𝚑𝚊𝚍𝚘𝚠 𝚊𝚍𝚖𝚒𝚗",
  DEV_NAME: "Shadow"
};

const PORT = process.env.PORT || 3000;
http.createServer((req, res) => res.end("ok")).listen(PORT);

const appState = JSON.parse(fs.readFileSync("appState.json", "utf8"));

function loadData() {
  try {
    return JSON.parse(fs.readFileSync("data.json", "utf8"));
  } catch {
    return { prefix: "!", freePrefix: false, protected: {}, savedMessages: [], admins: [], locked: {} };
  }
}

function saveData(data) {
  fs.writeFileSync("data.json", JSON.stringify(data, null, 2));
}

const commands = {};
fs.readdirSync("./commands").forEach(file => {
  if (file.endsWith(".js")) {
    commands[file.replace(".js", "")] = require(`./commands/${file}`);
  }
});

const events = {};
fs.readdirSync("./events").forEach(file => {
  if (file.endsWith(".js")) {
    events[file.replace(".js", "")] = require(`./events/${file}`);
  }
});

const automicTimers = {};
const botSentMessages = {};
const startTime = Date.now();

function trackMsg(threadID, msgID) {
  if (!threadID || !msgID) return;
  if (!botSentMessages[threadID]) botSentMessages[threadID] = [];
  botSentMessages[threadID].push(msgID);
  if (botSentMessages[threadID].length > 60) botSentMessages[threadID].shift();
}

ws3.login({ appState }, (err, api) => {
  if (err) return console.log("خطأ في تسجيل الدخول:", err);

  const BOT_ID = api.getCurrentUserID();
  console.log("✅ يعمل | ID:", BOT_ID);

  const _origSend = api.sendMessage.bind(api);
  api.sendMessage = (msg, threadID, cb) => {
    if (typeof cb === "function") {
      return _origSend(msg, threadID, (e2, info) => {
        if (!e2 && info?.messageID) trackMsg(threadID, info.messageID);
        cb(e2, info);
      });
    }
    const p = _origSend(msg, threadID);
    if (p && typeof p.then === "function") {
      return p.then(info => {
        if (info?.messageID) trackMsg(threadID, info.messageID);
        return info;
      });
    }
    return p;
  };

  const hostingInfo = { platform: os.platform(), arch: os.arch(), node: process.version };

  api.listenMqtt((err, event) => {
    if (err || !event) return;

    for (const e in events) {
      try { events[e](api, event, config, loadData, saveData, automicTimers, BOT_ID, startTime); } catch {}
    }

    if (!event.body) return;

    const data = loadData();
    const admins = data.admins || [];
    const isAllowed = event.senderID === config.DEV_ID || admins.includes(event.senderID);
    if (!isAllowed) return;

    const PREFIX = data.prefix || "!";
    const body = event.body.trim();
    let cmd = null, args = [];

    if (body.startsWith(PREFIX)) {
      args = body.slice(PREFIX.length).trim().split(" ");
      cmd = args[0].toLowerCase();
    } else if (data.freePrefix) {
      args = body.trim().split(" ");
      cmd = args[0].toLowerCase();
    }

    if (!cmd || !commands[cmd]) return;

    try {
      const result = commands[cmd](
        api, event, args, startTime,
        loadData, saveData, automicTimers,
        config, hostingInfo, botSentMessages, BOT_ID
      );
      if (result?.catch) result.catch(e => console.log("خطأ:", e.message));
    } catch (e) {
      console.log("خطأ:", e.message);
    }
  });
});

module.exports = (api, event, config, loadData, saveData, automicTimers, BOT_ID, startTime) => {
  if (event.logMessageType !== "log:subscribe") return;

  const threadID = event.threadID;
  const botID = String(BOT_ID || api.getCurrentUserID());
  const added = event.logMessageData?.addedParticipants || [];
  const botJoined = added.some(p => String(p.userFbId || p.id || "") === botID);

  if (!botJoined) return;

  // Set bot and dev nicknames
  setTimeout(() => {
    try { api.setNickname(config.BOT_NICK, threadID, botID); } catch {}
  }, 2000);

  setTimeout(async () => {
    try {
      const info = await api.getThreadInfo(threadID);
      if ((info.participantIDs || []).map(String).includes(String(config.DEV_ID))) {
        api.setNickname(config.DEV_NICK, threadID, config.DEV_ID);
      }
    } catch {}
  }, 2500);

  // Send welcome message after nicknames are set
  setTimeout(() => {
    try {
      const data = loadData();
      const prefix = data.prefix || "!";
      const diff = Date.now() - (startTime || Date.now());
      const s = Math.floor(diff / 1000) % 60;
      const m = Math.floor(diff / 60000) % 60;
      const h = Math.floor(diff / 3600000);
      const uptime = `${h > 0 ? h + "s " : ""}${m > 0 ? m + "m " : ""}${s}s`;

      const msg =
`${config.BOT_NAME}
dev: ${config.DEV_NAME}
prefix: ${prefix}
uptime: ${uptime}`;

      api.sendMessage(msg, threadID);
    } catch {}
  }, 4000);
};

const cooldowns = {};
const nickCooldowns = {};

module.exports = (api, event, config, loadData, saveData, automicTimers, BOT_ID) => {
  const data = loadData();
  const threadID = event.threadID;
  const botID = String(BOT_ID || api.getCurrentUserID());
  const devID = String(config.DEV_ID);
  const changerID = String(event.author || event.senderID || "");

  // قفل الإضافة — re-add anyone who leaves
  if (event.logMessageType === "log:unsubscribe") {
    if (data.locked?.[threadID]) {
      const leftID = String(
        event.logMessageData?.leftParticipantFbId ||
        event.logMessageData?.participantId ||
        event.author || ""
      );
      if (leftID && leftID !== botID) {
        setTimeout(() => {
          try { api.gcmember("add", leftID, threadID); } catch {}
        }, 1000);
      }
    }
    return;
  }

  // Protect bot and dev nicknames (always, regardless of protection toggle)
  if (event.logMessageType === "log:user-nickname") {
    const targetID = String(event.logMessageData?.participant_id || "");
    const now = Date.now();

    if (targetID === botID && changerID !== botID) {
      const key = `bot_${threadID}`;
      if (now - (nickCooldowns[key] || 0) > 8000) {
        nickCooldowns[key] = now;
        setTimeout(() => {
          try { api.setNickname(config.BOT_NICK, threadID, botID); } catch {}
        }, 1500);
      }
      return;
    }

    if (targetID === devID && changerID !== botID && changerID !== devID) {
      const key = `dev_${threadID}`;
      if (now - (nickCooldowns[key] || 0) > 8000) {
        nickCooldowns[key] = now;
        setTimeout(() => {
          try { api.setNickname(config.DEV_NICK, threadID, devID); } catch {}
        }, 1500);
      }
      return;
    }
  }

  // Full group protection
  if (!data.protected?.[threadID]?.active) return;
  if (changerID === devID || changerID === botID) return;

  const protection = data.protected[threadID];
  const now = Date.now();
  if (now - (cooldowns[threadID] || 0) < 4000) return;

  if (event.logMessageType === "log:thread-name") {
    const newName = event.logMessageData?.name;
    const oldName = protection.threadName;
    if (newName && newName !== oldName) {
      cooldowns[threadID] = now;
      api.gcname(oldName, threadID).catch(() => {});
    }
  }

  if (event.logMessageType === "log:user-nickname") {
    const targetID = String(event.logMessageData?.participant_id || "");
    const oldNick = protection.nicknames?.[targetID] ?? "";
    const newNick = event.logMessageData?.nickname ?? "";
    if (newNick !== oldNick) {
      cooldowns[threadID] = now;
      setTimeout(() => {
        try { api.setNickname(oldNick, threadID, targetID); } catch {}
      }, 1500);
    }
  }
};

module.exports = (api, event, args, startTime, loadData, saveData) => {
  const threadID = event.threadID;
  const data = loadData();
  if (!data.locked) data.locked = {};

  const isOn = data.locked[threadID];
  data.locked[threadID] = !isOn;
  saveData(data);

  api.sendMessage(data.locked[threadID] ? "قفل الإضافة: تفعيل" : "قفل الإضافة: إيقاف", threadID);
};

module.exports = (api, event, args, startTime, loadData, saveData) => {
  const threadID = event.threadID;
  const data = loadData();
  if (!data.savedMessages) data.savedMessages = [];

  if (args[1] === "حذف") {
    const num = parseInt(args[2], 10);
    if (!num || num < 1 || num > data.savedMessages.length) return;
    const removed = data.savedMessages.splice(num - 1, 1)[0];
    if (data.selectedMessage === removed) data.selectedMessage = data.savedMessages[0] || null;
    saveData(data);
    return;
  }

  if (args[1] === "اختيار") {
    const num = parseInt(args[2], 10);
    if (!num || num < 1 || num > data.savedMessages.length) return;
    data.selectedMessage = data.savedMessages[num - 1];
    saveData(data);
    return api.sendMessage(`الرسالة ${num} محددة للاتوميك.`, threadID);
  }

  if (!event.messageReply) {
    const msgs = data.savedMessages;
    if (msgs.length === 0) return api.sendMessage("لا توجد رسائل محفوظة.", threadID);
    const selected = data.selectedMessage;
    const list = msgs.map((m, i) => `${i + 1}. ${m.slice(0, 50)}${m === selected ? " ◄" : ""}`).join("\n");
    return api.sendMessage(list, threadID);
  }

  const body = event.messageReply.body;
  if (!body?.trim()) return;

  const exists = data.savedMessages.indexOf(body);
  if (exists !== -1) {
    data.selectedMessage = body;
    saveData(data);
    return api.sendMessage(`رقم ${exists + 1} محددة.`, threadID);
  }

  data.savedMessages.push(body);
  data.selectedMessage = body;
  saveData(data);
  api.sendMessage(`حُفظت رقم ${data.savedMessages.length}.`, threadID);
};

const pendingNav = {};

module.exports = async (api, event, args, startTime, loadData, saveData, automicTimers, config) => {
  const threadID = event.threadID;
  const senderID = event.senderID;
  const data = loadData();
  const prefix = data.prefix || "!";

  if (args[1] && !isNaN(parseInt(args[1]))) {
    const cache = pendingNav[senderID];
    if (!cache?.threads) return api.sendMessage("اكتب !قروبات أولاً.", threadID);

    const num = parseInt(args[1]) - 1;
    if (num < 0 || num >= cache.threads.length) return;

    const chosen = cache.threads[num];
    delete pendingNav[senderID];
    const targetThread = chosen.threadID;

    try {
      await new Promise(r => api.gcmember("add", config.DEV_ID, targetThread, () => r()));
    } catch {}

    await new Promise(r => setTimeout(r, 2000));

    try {
      await api.sendMessage(`${config.BOT_NAME} online`, targetThread);
    } catch {}
    return;
  }

  try {
    const threads = await api.getThreadList(30, null, ["INBOX"]);
    const groups = (threads || []).filter(t => t.isGroup);
    if (groups.length === 0) return api.sendMessage("البوت مش في أي جروب.", threadID);

    pendingNav[senderID] = { threads: groups };
    setTimeout(() => { delete pendingNav[senderID]; }, 90000);

    const list = groups.map((g, i) =>
      `${i + 1}. ${g.threadName || "بدون اسم"} (${g.participantIDs?.length || 0})`
    ).join("\n");

    api.sendMessage(`${list}\n\n${prefix}قروبات [رقم] للدخول`, threadID);
  } catch {
    api.sendMessage("فشل جلب القائمة.", threadID);
  }
};

